function checkUserSpeed(arr) {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      let slow = false;
      for (let obj of arr) {
        if (obj.actual === 0 || obj.actual < 0) {
          reject("rejected");
          return;
        }
        if (obj.actual < obj.required) {
          slow = true;
        }

      }

      if (slow) {
        resolve("slow");
      }
      else {
        resolve("fast");
      }



    }, 700);
  })

}

checkUserSpeed([
  { required: 50, actual: 70 },
  { required: 40, actual: 20 }
])
.then(res => console.log(res))
.catch(err => console.log(err));